import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const h=JSON.parse('{"title":"Tier表（覚醒体評価ランキング）","description":"","frontmatter":{},"headers":[],"relativePath":"ja/guides/tier-list.md","filePath":"ja/guides/tier-list.md","lastUpdated":1775394001000}'),n={name:"ja/guides/tier-list.md"};function r(i,t,s,g,x,y){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="tier表-覚醒体評価ランキング" tabindex="-1">Tier表（覚醒体評価ランキング） <a class="header-anchor" href="#tier表-覚醒体評価ランキング" aria-label="Permalink to &quot;Tier表（覚醒体評価ランキング）&quot;">​</a></h1><p>忘却前夜（Morimens）の覚醒体Tier表です。各コンテンツにおける評価をランキング形式で掲載しています。</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><span class="server-badge server-jp">JP</span> 本Tier表はv2.4時点のデータに基づいています。CN/グローバルサーバーとはバランス調整が異なるため、評価が異なる場合があります。GameKee Wikiのランキングを参考にしていますが、最新版本と一致しない可能性があります。</p></div><h2 id="tier基準" tabindex="-1">Tier基準 <a class="header-anchor" href="#tier基準" aria-label="Permalink to &quot;Tier基準&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">Tier</th><th style="text-align:left;">評価</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>T0</strong></td><td style="text-align:left;">環境最強。あらゆるコンテンツで最高のパフォーマンス</td></tr><tr><td style="text-align:center;"><strong>T1</strong></td><td style="text-align:left;">非常に強力。大半のコンテンツで活躍</td></tr><tr><td style="text-align:center;"><strong>T2</strong></td><td style="text-align:left;">優秀。特定のコンテンツや編成で輝く</td></tr><tr><td style="text-align:center;"><strong>T3</strong></td><td style="text-align:left;">平均的。育成すれば十分に活躍可能</td></tr></tbody></table><h2 id="総合tier表" tabindex="-1">総合Tier表 <a class="header-anchor" href="#総合tier表" aria-label="Permalink to &quot;総合Tier表&quot;">​</a></h2><h3 id="ssr覚醒体" tabindex="-1">SSR覚醒体 <a class="header-anchor" href="#ssr覚醒体" aria-label="Permalink to &quot;SSR覚醒体&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">Tier</th><th style="text-align:left;">覚醒体</th></tr></thead><tbody><tr><td style="text-align:center;">T0</td><td style="text-align:left;">艾尔瓦 (Alva)、朵尔 (Doll)、環行·拉蒙娜 (Ramona: Timeworn)、图鲁 (Tulu)、尤乌哈希 (Uvhash)、雷娅 (Rhea)、索蕾尔 (Sorel)、艾瑞卡 (Erica)、莉兹 (Liz)、达芙黛尔 (Daffodil)、24</td></tr><tr><td style="text-align:center;">T1</td><td style="text-align:left;">奥吉尔 (Ogier)、萝坦 (Lotan)、拉蒙娜 (Ramona)、莉莉 (Lily)、淡墨 (Danmo)、希莱斯特 (Celeste)、戈利亚 (Goliath)、珊 (Shan)、爱丽丝 (Alice)、温柯尔 (Winkle)、卡茜亚 (Casiah)、詹金 (Jenkins)</td></tr><tr><td style="text-align:center;">T2</td><td style="text-align:left;">潘狄娅 (Pandya)、诺缔拉 (Nodera)、奥瑞塔 (Aurita)、凯刻斯 (Caecus)、菲茵特 (Faint)、阿格里帕 (Agrippa)、汀克特 (Tincture)</td></tr><tr><td style="text-align:center;">T3</td><td style="text-align:left;">伽伦 (Galen)、宁菲亚 (Nymphia)、法洛思 (Faros)、希洛 (Shilo)</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Tier未評定のキャラクター（弥利亚姆、泰旖丝、墨菲、萨尔瓦多、塔薇、哈姆林、莱克、旺达、奥尔拉、艾继丝、各星辰篇限定キャラ等）は、限定入手かつ環境トップクラスの性能を持つものが多いです。入手できれば即戦力になります。</p></div><h2 id="コンテンツ別tier表" tabindex="-1">コンテンツ別Tier表 <a class="header-anchor" href="#コンテンツ別tier表" aria-label="Permalink to &quot;コンテンツ別Tier表&quot;">​</a></h2><h3 id="調査行動-investigation" tabindex="-1">調査行動（Investigation） <a class="header-anchor" href="#調査行動-investigation" aria-label="Permalink to &quot;調査行動（Investigation）&quot;">​</a></h3><p>主に24、图鲁、尤乌哈希といったT0メインCが活躍。莉兹の毒チームも低コストで攻略可能。凯刻斯の反撃チームは高練度で安定した通関が可能。</p><h3 id="相位対局-phase-chess-pvp" tabindex="-1">相位対局（Phase Chess / PvP） <a class="header-anchor" href="#相位対局-phase-chess-pvp" aria-label="Permalink to &quot;相位対局（Phase Chess / PvP）&quot;">​</a></h3><p>PVPはBeta段階のため環境が流動的。御四家（拉蒙娜・萝坦・朵尔・奥吉尔）が基本編成。潘狄娅は嘲諷を無視して後衛を狙撃できるため高評価。</p><h3 id="融災禁区-dissolution-zone" tabindex="-1">融災禁区（Dissolution Zone） <a class="header-anchor" href="#融災禁区-dissolution-zone" aria-label="Permalink to &quot;融災禁区（Dissolution Zone）&quot;">​</a></h3><p>多チーム終局コンテンツ。覚醒体・運命の輪・鍵令の重複不可のため、幅広いキャラ育成が必要。24は単独でチームを支えられるため最優先。</p><h3 id="幻夢深潜-phantasmal-dive" tabindex="-1">幻夢深潜（Phantasmal Dive） <a class="header-anchor" href="#幻夢深潜-phantasmal-dive" aria-label="Permalink to &quot;幻夢深潜（Phantasmal Dive）&quot;">​</a></h3><p>Roguelikeモード。深潜三杰（奥瑞塔・艾瑞卡・艾继丝）が高パフォーマンスを発揮。</p><h2 id="界域別評価" tabindex="-1">界域別評価 <a class="header-anchor" href="#界域別評価" aria-label="Permalink to &quot;界域別評価&quot;">​</a></h2><h3 id="混沌" tabindex="-1"><span class="realm-badge realm-chaos">混沌</span> <a class="header-anchor" href="#混沌" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-chaos&quot;&gt;混沌&lt;/span&gt;&quot;">​</a></h3><p><strong>界域ランク：A+</strong>（24が単独で界域全体を支えているが、完全な編成深度に欠ける）</p><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体</th><th style="text-align:center;">Tier</th><th style="text-align:center;">役割</th><th style="text-align:left;">コメント</th></tr></thead><tbody><tr><td style="text-align:left;">24</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">全ゲーム最強の汎用キャラ。全界域に適応可能。必須入手</td></tr><tr><td style="text-align:left;">艾尔瓦 (Alva)</td><td style="text-align:center;">T0</td><td style="text-align:center;">防御</td><td style="text-align:left;">混沌コアキャラ</td></tr><tr><td style="text-align:left;">朵尔 (Doll)</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">混沌メインC</td></tr><tr><td style="text-align:left;">環行·拉蒙娜</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">限定。拉蒙娜の変体形態</td></tr><tr><td style="text-align:left;">塔薇 (Tawil)</td><td style="text-align:center;">—</td><td style="text-align:center;">支援</td><td style="text-align:left;">辅助定位だがメインCとしても運用可能。超限後ダメージ+35%</td></tr><tr><td style="text-align:left;">莉莉 (Lily)</td><td style="text-align:center;">T1</td><td style="text-align:center;">防御</td><td style="text-align:left;">混沌チームの回復・防御の要</td></tr><tr><td style="text-align:left;">哈姆林 (Hameln)</td><td style="text-align:center;">—</td><td style="text-align:center;">支援</td><td style="text-align:left;">爆発ダメージと銀鍵充能が強力。凯刻斯反撃チームで活躍</td></tr><tr><td style="text-align:left;">淡墨 (Danmo)</td><td style="text-align:center;">T1</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">限定。満配後の火力は極めて高い</td></tr></tbody></table><h3 id="深海" tabindex="-1"><span class="realm-badge realm-aequor">深海</span> <a class="header-anchor" href="#深海" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-aequor&quot;&gt;深海&lt;/span&gt;&quot;">​</a></h3><p><strong>界域ランク：S</strong>（強化後、現環境最強界域）</p><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体</th><th style="text-align:center;">Tier</th><th style="text-align:center;">役割</th><th style="text-align:left;">コメント</th></tr></thead><tbody><tr><td style="text-align:left;">图鲁 (Tulu)</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">深海メインC。v1.4で大幅強化</td></tr><tr><td style="text-align:left;">墨菲 (Murphy)</td><td style="text-align:center;">—</td><td style="text-align:center;">防御</td><td style="text-align:left;">深海プレイヤー必須。「献祭」パッシブが強力</td></tr><tr><td style="text-align:left;">弥利亚姆 (Miryam)</td><td style="text-align:center;">—</td><td style="text-align:center;">支援</td><td style="text-align:left;">限定。触腕補助の要。v1.4で強化</td></tr><tr><td style="text-align:left;">希莱斯特 (Celeste)</td><td style="text-align:center;">T1</td><td style="text-align:center;">支援</td><td style="text-align:left;">回復・復活持ち。汎用性が高い</td></tr><tr><td style="text-align:left;">凯刻斯 (Caecus)</td><td style="text-align:center;">T2</td><td style="text-align:center;">副攻撃</td><td style="text-align:left;">反撃コア。3覚醒後に防御カードが反撃暴撃を発動</td></tr><tr><td style="text-align:left;">戈利亚 (Goliath)</td><td style="text-align:center;">T1</td><td style="text-align:center;">防御</td><td style="text-align:left;">凯刻斯反撃チームでの増傷要員</td></tr><tr><td style="text-align:left;">奥瑞塔 (Aurita)</td><td style="text-align:center;">T2</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">無料SSR。深海の万能アタッカー</td></tr><tr><td style="text-align:left;">珊 (Shan)</td><td style="text-align:center;">T1</td><td style="text-align:center;">副攻撃</td><td style="text-align:left;">シールド型DPS</td></tr></tbody></table><h3 id="血肉" tabindex="-1"><span class="realm-badge realm-caro">血肉</span> <a class="header-anchor" href="#血肉" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-caro&quot;&gt;血肉&lt;/span&gt;&quot;">​</a></h3><p><strong>界域ランク：S</strong>（神父+専属運命の輪で深海と並ぶS級）</p><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体</th><th style="text-align:center;">Tier</th><th style="text-align:center;">役割</th><th style="text-align:left;">コメント</th></tr></thead><tbody><tr><td style="text-align:left;">尤乌哈希 (Uvhash)</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">血肉メインC</td></tr><tr><td style="text-align:left;">雷娅 (Rhea)</td><td style="text-align:center;">T0</td><td style="text-align:center;">支援</td><td style="text-align:left;">血肉チーム不可欠の「2」の片割れ。胚胎吞噬で大量回復</td></tr><tr><td style="text-align:left;">索蕾尔 (Sorel)</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">限定。「紅女王」</td></tr><tr><td style="text-align:left;">萨尔瓦多 (Salvador)</td><td style="text-align:center;">—</td><td style="text-align:center;">防御</td><td style="text-align:left;">「神父」。専属運命の輪で血肉をS級に押し上げた。Top3最強編成の核</td></tr><tr><td style="text-align:left;">艾继丝 (Aigis)</td><td style="text-align:center;">—</td><td style="text-align:center;">支援</td><td style="text-align:left;">無料SSR。血肉チームの「2」のもう片方。群体易傷+AOE</td></tr><tr><td style="text-align:left;">泰旖丝 (Thais)</td><td style="text-align:center;">—</td><td style="text-align:center;">支援</td><td style="text-align:left;">限定。S級血肉コアユニット</td></tr><tr><td style="text-align:left;">菲茵特 (Faint)</td><td style="text-align:center;">T2</td><td style="text-align:center;">副攻撃</td><td style="text-align:left;">死亡抵抗発動後に全チーム回復強化</td></tr></tbody></table><h3 id="超維" tabindex="-1"><span class="realm-badge realm-ultra">超維</span> <a class="header-anchor" href="#超維" aria-label="Permalink to &quot;&lt;span class=&quot;realm-badge realm-ultra&quot;&gt;超維&lt;/span&gt;&quot;">​</a></h3><p><strong>界域ランク：A</strong>（老舗の強チームだが、深海・血肉に追い越された）</p><table tabindex="0"><thead><tr><th style="text-align:left;">覚醒体</th><th style="text-align:center;">Tier</th><th style="text-align:center;">役割</th><th style="text-align:left;">コメント</th></tr></thead><tbody><tr><td style="text-align:left;">艾瑞卡 (Erica)</td><td style="text-align:center;">T0</td><td style="text-align:center;">防御</td><td style="text-align:left;">無料SSR。超維チームのコアタンク</td></tr><tr><td style="text-align:left;">莉兹 (Liz)</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">「青炎舞者」。毒チームで新規プレイヤーに最適</td></tr><tr><td style="text-align:left;">达芙黛尔 (Daffodil)</td><td style="text-align:center;">T0</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">限定。「水仙夫人」。v1.1リメイク済み</td></tr><tr><td style="text-align:left;">旺达 (Wanda)</td><td style="text-align:center;">—</td><td style="text-align:center;">防御</td><td style="text-align:left;">盾反チーム。毒チーム必須キャラ</td></tr><tr><td style="text-align:left;">奥尔拉 (Horla)</td><td style="text-align:center;">—</td><td style="text-align:center;">支援</td><td style="text-align:left;">超維開荒チームのコア補助</td></tr><tr><td style="text-align:left;">温柯尔 (Winkle)</td><td style="text-align:center;">T1</td><td style="text-align:center;">支援</td><td style="text-align:left;">飛蛾火で緑炎スタック。多段攻撃時に有効</td></tr><tr><td style="text-align:left;">波吕克斯 (Pollux)</td><td style="text-align:center;">—</td><td style="text-align:center;">攻撃</td><td style="text-align:left;">限定。星辰篇の超維アタッカー</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Tier表はあくまで目安です。啓霊（凸）状況や編成との相性によって評価は大きく変わります。手持ちのキャラクターを活かす編成を考えましょう。</p></div><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../awakeners/list.html">覚醒体一覧</a></li><li><a href="./../awakeners/team-building.html">編成ガイド</a></li><li><a href="./beginner.html">初心者ガイド</a></li></ul>',34)])])}const c=e(n,[["render",r]]);export{h as __pageData,c as default};
